// YouTube Sentinel Agent
// Monitors all brand channels for new uploads and triggers content generation

const channels = [
  {
    id: $env.DAX_TRAVELER_CHANNEL_ID,
    name: 'Dax The Traveler',
    brand: 'dax_traveler',
    enabled: $env.BRAND_DAX_TRAVELER_ENABLED === 'true'
  },
  {
    id: $env.GODS_VESSEL_CHANNEL_ID,
    name: "God's Vessel",
    brand: 'gods_vessel',
    enabled: $env.BRAND_GODS_VESSEL_ENABLED === 'true'
  },
  {
    id: $env.TIMEZONE_TRAVELERS_CHANNEL_ID,
    name: 'Time-Zone Travelers',
    brand: 'timezone_travelers',
    enabled: $env.BRAND_TIMEZONE_TRAVELERS_ENABLED === 'true'
  },
  {
    id: $env.ANI_DAX_CHANNEL_ID,
    name: 'Ani-Dax',
    brand: 'ani_dax',
    enabled: $env.BRAND_ANI_DAX_ENABLED === 'true'
  }
];

// Filter enabled channels
const enabledChannels = channels.filter(channel => channel.enabled && channel.id);

return enabledChannels.map(channel => ({
  channelId: channel.id,
  channelName: channel.name,
  brand: channel.brand,
  apiKey: $env.YOUTUBE_API_KEY
}));

// Process YouTube API response and check for new videos
const response = $input.first();
const channelData = $('Process Each Channel').first();

if (!response.items || response.items.length === 0) {
  return [];
}

// Get last processed video from static data
const staticData = $workflow.staticData || {};
const lastProcessedKey = `${channelData.brand}_last_video_id`;
const lastProcessedVideoId = staticData[lastProcessedKey];

const newVideos = [];
let latestVideoId = null;

for (const video of response.items) {
  const videoId = video.id.videoId;

  // Track the latest video ID
  if (!latestVideoId) {
    latestVideoId = videoId;
  }

  // If this is the last processed video, stop here
  if (videoId === lastProcessedVideoId) {
    break;
  }

  // This is a new video
  newVideos.push({
    videoId,
    title: video.snippet.title,
    description: video.snippet.description,
    publishedAt: video.snippet.publishedAt,
    thumbnailUrl: video.snippet.thumbnails.high?.url || video.snippet.thumbnails.default.url,
    channelId: channelData.channelId,
    channelName: channelData.channelName,
    brand: channelData.brand,
    videoUrl: `https://www.youtube.com/watch?v=${videoId}`
  });
}

// Update static data with latest video ID
if (latestVideoId) {
  staticData[lastProcessedKey] = latestVideoId;
}

return newVideos;

// Extract transcript and analyze content
const videoData = $('Process Each Video').first();
const captionsResponse = $input.first();

let transcript = '';
let hasTranscript = false;

// Check if captions are available
if (captionsResponse.items && captionsResponse.items.length > 0) {
  // For now, we'll use the description as content since caption download requires OAuth
  transcript = videoData.description;
  hasTranscript = true;
} else {
  // Use title and description for content analysis
  transcript = `${videoData.title}\n\n${videoData.description}`;
}

// Analyze content for key themes and topics
function extractKeywords(text) {
  const words = text.toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .split(/\s+/)
    .filter(word => word.length > 3);

  const frequency = {};
  words.forEach(word => {
    frequency[word] = (frequency[word] || 0) + 1;
  });

  return Object.entries(frequency)
    .sort(([,a], [,b]) => b - a)
    .slice(0, 10)
    .map(([word]) => word);
}

function extractTopics(text, brand) {
  const topics = [];
  const lowerText = text.toLowerCase();

  // Brand-specific topic extraction
  if (brand === 'dax_traveler' || brand === 'timezone_travelers') {
    const travelKeywords = ['travel', 'destination', 'trip', 'adventure', 'explore', 'journey', 'vacation', 'backpack', 'culture', 'food'];
    topics.push(...travelKeywords.filter(keyword => lowerText.includes(keyword)));
  }

  if (brand === 'gods_vessel') {
    const faithKeywords = ['faith', 'god', 'jesus', 'prayer', 'bible', 'christian', 'worship', 'blessing', 'grace', 'love'];
    topics.push(...faithKeywords.filter(keyword => lowerText.includes(keyword)));
  }

  if (brand === 'ani_dax') {
    const animeKeywords = ['anime', 'manga', 'otaku', 'cosplay', 'japan', 'character', 'series', 'episode', 'review', 'recommendation'];
    topics.push(...animeKeywords.filter(keyword => lowerText.includes(keyword)));
  }

  return [...new Set(topics)];
}

const keywords = extractKeywords(transcript);
const topics = extractTopics(transcript, videoData.brand);

// Create content analysis
const contentAnalysis = {
  ...videoData,
  transcript,
  hasTranscript,
  keywords,
  topics,
  contentLength: transcript.length,
  analysisTimestamp: new Date().toISOString(),
  readyForContentGeneration: true
};

return contentAnalysis;

